<?php
namespace App\Http\Controllers;
use App\Models\Product;use Illuminate\Http\{RedirectResponse,Request};use Illuminate\View\View;
class CartController extends Controller{public function index():View{return view('cart.index',$this->summary());}public function add(Request $r,Product $product):RedirectResponse{$qty=max(1,(int)$r->input('quantity',1));$cart=session('cart',[]);$cart[$product->id]=['id'=>$product->id,'name'=>$product->name,'slug'=>$product->slug,'image'=>$product->image,'price'=>$product->final_price,'quantity'=>($cart[$product->id]['quantity']??0)+$qty];session(['cart'=>$cart]);return back()->with('success','محصول به سبد خرید اضافه شد.');}public function update(Request $r,Product $product):RedirectResponse{$cart=session('cart',[]);if(isset($cart[$product->id])){$cart[$product->id]['quantity']=max(1,(int)$r->quantity);session(['cart'=>$cart]);}return back();}public function remove(Product $product):RedirectResponse{$cart=session('cart',[]);unset($cart[$product->id]);session(['cart'=>$cart]);return back()->with('success','محصول حذف شد.');}private function summary():array{$items=collect(session('cart',[]));$total=$items->sum(fn($i)=>$i['price']*$i['quantity']);$discount=$total>10000000?$total*.05:0;return ['items'=>$items,'total'=>$total,'discount'=>$discount,'final'=>$total-$discount];}}
